import React, { useState, useCallback } from "react";
import { useNavigate, Link } from "react-router-dom";
import { authAPI } from "../services/api";

const Login = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  // 🔁 Redirect based on role (matches backend)
  const redirectUser = useCallback(
    (user) => {
      if (user.role === "admin") {
        navigate("/admin/dashboard", { replace: true });
      } else if (user.role === "staff") {
        navigate("/staff/dashboard", { replace: true });
      } else if (user.role === "student") {
        if (!user.profileCompleted) {
          navigate("/complete-profile", { replace: true });
        } else {
          navigate("/student/events", { replace: true });
        }
      } else {
        navigate("/events", { replace: true });
      }
    },
    [navigate]
  );

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");

    if (!email || !password) {
      setError("Please enter email and password");
      return;
    }

    setLoading(true);

    try {
      const res = await authAPI.login({ email, password ,  role: userType
});

      // 🔐 OTP flow (Email + SMS)
      if (res.data.otpRequired) {
        navigate("/verify-otp", {
          state: { userId: res.data.userId },
        });
        return;
      }

      // ✅ Normal login
      localStorage.setItem("token", res.data.token);
      localStorage.setItem("user", JSON.stringify(res.data));

      redirectUser(res.data);
    } catch (err) {
      setError(
        err.response?.data?.message ||
          "Invalid login credentials. Please try again."
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-100 px-4">
      <div className="w-full max-w-md bg-white rounded-xl shadow-md p-8 text-gray-600">
        <h2 className="text-2xl font-semibold text-center text-gray-800 mb-2">
          Welcome
        </h2>
        <p className="text-sm text-center mb-6">
          Sign in to your account
        </p>

        {/* ERROR MESSAGE */}
        {error && (
          <div className="bg-red-100 text-red-700 px-4 py-2 rounded-lg mb-4 text-sm">
            {error}
          </div>
        )}

        <form onSubmit={handleLogin}>
          <input
            type="email"
            placeholder="Enter your email"
            className="w-full border border-gray-300 rounded-full px-4 py-2 mb-3 focus:outline-none focus:ring-2 focus:ring-indigo-500"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />

          <input
            type="password"
            placeholder="Enter your password"
            className="w-full border border-gray-300 rounded-full px-4 py-2 mb-2 focus:outline-none focus:ring-2 focus:ring-indigo-500"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <Link
            to="/forgot-password"
            className="block text-right text-sm text-blue-600 underline mb-4"
          >
            Forgot Password?
          </Link>

          <button
            type="submit"
            disabled={loading}
            className={`w-full rounded-full py-2 text-white font-medium transition
              ${
                loading
                  ? "bg-gray-400 cursor-not-allowed"
                  : "bg-indigo-600 hover:bg-indigo-700"
              }`}
          >
            {loading ? "Logging in..." : "Log in"}
          </button>
        </form>

        <div className="text-center mt-6 pt-6 border-t">
          <p className="text-sm mb-2">Don't have an account?</p>
          <button
            onClick={() => navigate("/register")}
            className="w-full rounded-full py-2 border border-indigo-600 text-indigo-600 font-medium hover:bg-indigo-600 hover:text-white transition"
          >
            Create Account
          </button>
        </div>
      </div>
    </div>
  );
};

export default Login;
